#!/bin/bash
set -e

TARGET="/Users/nimrod/projects/shaked-wg-agent"
cd "$TARGET"

echo "📁 Creating data/ directory..."
mkdir -p data

echo "📄 Writing data files..."

base64 -d << 'EOF' > data/config.json

EOF

base64 -d << 'EOF' > data/sources.json

EOF

base64 -d << 'EOF' > data/runs.json

EOF

base64 -d << 'LISTEOF' > data/listings.json

LISTEOF

printf '%s\n' '# OS' '.DS_Store' 'Thumbs.db' '' '# Editor' '.vscode/' '.idea/' '*.swp' '*.swo' '' '# Logs' '*.log' '' '# Local overrides' '*.local.json' > .gitignore

echo "✅ All data files created"
ls -la data/

echo ""
echo "📝 Committing..."
git add .
git commit -m "feat: initial MVP — Shaked WG Basel agent"

echo ""
echo "🚀 Pushing to GitHub..."
git push -u origin main

echo ""
echo "🌿 Creating dev branch..."
git checkout -b dev
git push -u origin dev

echo ""
echo "✅ Done! Repo is live at: https://github.com/WaldNimrod/shaked-wg-agent"
